  // Layer 0: 5 -> 64
  List<double> h1 = List.filled(64, 0.0);
  for (int j = 0; j < 64; j++) {
    double s = biases0[j];
    for (int k = 0; k < x.length; k++) {
      s += x[k] * weights0[k][j];
    }
    h1[j] = s > 0 ? s : 0.0;  // ReLU
  }
  x = h1;

  // Layer 1: 64 -> 32
  List<double> h2 = List.filled(32, 0.0);
  for (int j = 0; j < 32; j++) {
    double s = biases1[j];
    for (int k = 0; k < x.length; k++) {
      s += x[k] * weights1[k][j];
    }
    h2[j] = s > 0 ? s : 0.0;  // ReLU
  }
  x = h2;

  // Output layer: 3 outputs
  List<double> output = List.filled(3, 0.0);
  for (int j = 0; j < 3; j++) {
    double s = biases2[j];
    for (int k = 0; k < x.length; k++) {
      s += x[k] * weights2[k][j];
    }
    output[j] = s;
  }
  // Softmax for multi-class
  double max = output.reduce((a, b) => a > b ? a : b);
  double sum = 0;
  for (int j = 0; j < output.length; j++) {
    output[j] = exp(output[j] - max);
    sum += output[j];
  }
  double bestP = 0;
  int bestIdx = 0;
  for (int j = 0; j < output.length; j++) {
    output[j] /= sum;
    if (output[j] > bestP) { bestP = output[j]; bestIdx = j; }
  }
  return bestIdx.toDouble();
}

String predictLabel(List<double> input) {
  int idx = predictSmartLibrary(input).toInt();
  const labels = <int, String>{
    0: "Critical",
    1: "Optimal",
    2: "Sub Optimal",
  };
  return labels[idx] ?? "Unknown";
}